SET XACT_ABORT ON; BEGIN TRANSACTION;
CREATE TABLE Submissions(Id INT IDENTITY PRIMARY KEY,RequirementId INT NOT NULL,GroupId INT NOT NULL,Status NVARCHAR(30) NOT NULL DEFAULT'DRAFT',LatestAttemptNumber INT NOT NULL DEFAULT 0,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),UpdatedAt DATETIME2 NULL,FOREIGN KEY(RequirementId) REFERENCES SubmissionRequirements(Id),FOREIGN KEY(GroupId) REFERENCES StudentGroups(Id),UNIQUE(RequirementId,GroupId),CHECK(Status IN('DRAFT','SUBMITTED','LATE','RESUBMITTED','UNDER_REVIEW','REQUIRES_REVISION','GRADED')));
CREATE TABLE SubmissionAttempts(Id INT IDENTITY PRIMARY KEY,SubmissionId INT NOT NULL,AttemptNumber INT NOT NULL,Status NVARCHAR(30) NOT NULL,SubmittedBy INT NOT NULL,SubmittedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),IsLate BIT NOT NULL DEFAULT 0,FOREIGN KEY(SubmissionId) REFERENCES Submissions(Id),FOREIGN KEY(SubmittedBy) REFERENCES Users(Id),UNIQUE(SubmissionId,AttemptNumber));
CREATE TABLE SubmissionFiles(Id INT IDENTITY PRIMARY KEY,SubmissionAttemptId INT NOT NULL,ItemType NVARCHAR(30) NOT NULL,OriginalName NVARCHAR(260) NOT NULL,StoredName NVARCHAR(100) NOT NULL,RelativePath NVARCHAR(500) NOT NULL,MimeType NVARCHAR(150) NOT NULL,SizeBytes BIGINT NOT NULL,UploadedBy INT NOT NULL,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),FOREIGN KEY(SubmissionAttemptId) REFERENCES SubmissionAttempts(Id),FOREIGN KEY(UploadedBy) REFERENCES Users(Id),CHECK(ItemType IN('REPORT','SLIDE','SOURCE_CODE','OTHER')),CHECK(SizeBytes>0));
CREATE TABLE SubmissionLinks(Id INT IDENTITY PRIMARY KEY,SubmissionAttemptId INT NOT NULL,ItemType NVARCHAR(30) NOT NULL,Url NVARCHAR(2048) NOT NULL,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),FOREIGN KEY(SubmissionAttemptId) REFERENCES SubmissionAttempts(Id),UNIQUE(SubmissionAttemptId,ItemType),CHECK(ItemType IN('GITHUB_LINK','VIDEO_LINK')));
CREATE TABLE SubmissionHistory(Id INT IDENTITY PRIMARY KEY,SubmissionId INT NOT NULL,SubmissionAttemptId INT NULL,EventType NVARCHAR(50) NOT NULL,FromStatus NVARCHAR(30) NULL,ToStatus NVARCHAR(30) NOT NULL,ActorId INT NOT NULL,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),FOREIGN KEY(SubmissionId) REFERENCES Submissions(Id),FOREIGN KEY(SubmissionAttemptId) REFERENCES SubmissionAttempts(Id),FOREIGN KEY(ActorId) REFERENCES Users(Id));
CREATE INDEX IX_Submissions_Group ON Submissions(GroupId);CREATE INDEX IX_SubmissionAttempts_Submission ON SubmissionAttempts(SubmissionId,AttemptNumber DESC);CREATE INDEX IX_SubmissionFiles_Attempt ON SubmissionFiles(SubmissionAttemptId);CREATE INDEX IX_SubmissionHistory_Submission ON SubmissionHistory(SubmissionId,CreatedAt DESC);
COMMIT TRANSACTION;
